# Skeptic packet solve S43-T1-A-E2: three-route assess for contract gate
def assess(record: dict) -> str:
    required = {'digest_stable', 'dependency_layer_reused', 'lock_copied_before_source', 'source_change_rebuilds', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (not (not record["dependency_layer_reused"] and record["source_change_rebuilds"] > 3)) else 'REORDER_DOCKERFILE'

valid = {'case_id': 'CASO-TRU-043-1A', 'lock_copied_before_source': True, 'dependency_layer_reused': True, 'source_change_rebuilds': 1, 'digest_stable': True}
invalid = {'case_id': 'CASO-TRU-043-1A', 'lock_copied_before_source': False, 'dependency_layer_reused': False, 'source_change_rebuilds': 1000, 'digest_stable': False}
incomplete = {**valid}
incomplete.pop('digest_stable', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)
assert results[0] == 'PASS' and results[2].startswith('MISSING'), results

